(4, '2026-03-09 09:07:27', '2026-04-19 12:46:46', 'إكسسوارات قوالب الخرسانة | Concrete Formwork Accessories', 'Concrete Formwork Accessories', 'concrete-formwork-accessories', 'fa-cube', 'معدات وأدوات خاصة بأعمال قوالب الخرسانة.', 'categories/5JxNPJkb8kMX12BqIEoiARc5m6kEzAxziifkdrWq.jpg', 11, 5, 1, NULL, NULL, NULL, NULL, 0),
(5, '2026-03-09 09:07:27', '2026-04-19 12:47:03', 'العزل المائي والحراري | Waterproofing & Thermal Insulation', 'Waterproofing & Thermal Insulation', 'waterproofing-thermal-insulation', 'fa-shield-alt', 'مواد العزل المائي والحراري بأعلى معايير الجودة.', 'categories/IBu63lmZdr6I9m7LmmmHKLknQrPaQSjI8qbQ3JaB.jpg', 14, 6, 1, NULL, NULL, NULL, NULL, 0),
(6, '2026-03-09 09:07:27', '2026-04-19 12:47:38', 'مشابك الأنابيب والعلاقات | Pipe Clamps, Hangers & Fixings', 'Pipe Clamps, Hangers & Fixings', 'pipe-clamps-hangers-fixings', 'fa-link', 'أنظمة تثبيت متكاملة للأنابيب والكوابل.', 'categories/zffAity6jclpRbeBA4ONoRm2nbYgswJAICT4IKup.jpg', 9, 7, 1, NULL, NULL, NULL, NULL, 0),
(7, '2026-03-09 09:07:27', '2026-04-19 12:49:48', 'القواطع الجبسية والأسقف المعلقة | Gypsum Partitions & Suspended Ceilings', 'Gypsum Partitions & Suspended Ceilings', 'gypsum-partitions-suspended-ceilings', 'fa-border-all', 'حلول جبسية عصرية للمساحات الداخلية.', NULL, 15, 8, 1, NULL, NULL, NULL, NULL, 0),
(8, '2026-03-09 09:07:27', '2026-04-19 12:51:19', 'إكسسوارات الكلادينج والواجهات | Cladding & Facade Accessories', 'Cladding & Facade Accessories', 'cladding-facade-accessories', 'fa-layer-group', 'نظام متكامل لتكسية الواجهات بأعلى المعايير.', 'categories/7wnnhokCPp0WSg0AqVBGYsPYlIITVjwARRX5vWfh.jpg', 7, 9, 1, NULL, NULL, NULL, NULL, 0),
(9, '2026-03-09 09:07:27', '2026-04-25 10:57:44', 'المواد الاستهلاكية والأدوات | Consumable Items & Hardware', 'Consumable Items & Hardware', 'consumable-items-hardware', 'fa-screwdriver-wrench', 'تشكيلة واسعة من الأدوات المهنية والمواد الاستهلاكية.', 'categories/3l21K1OOTa0NNkkL5X4ayICw6utiF2YmwTrJPBlS.jpg', 6, 11, 1, NULL, NULL, NULL, NULL, 0),
(10, '2026-04-19 12:44:41', '2026-04-19 12:55:11', 'حلول هندسية لأعمال المعادن Metal Work Engineering Solution', 'Metal Work Engineering Solution', 'metal-work-engineering-solution', 'fa-folder', 'حلول هندسية متكاملة لأعمال المعادن تشمل التصميم والتصنيع والتركيب للهياكل المعدنية والدرابزين والأبواب والسياجات. نقدم لك منتجات عالية الجودة مصممة بدقة لتناسب مشاريعك السكنية والتجارية والصناعية مع ضمان المتانة والأمان.', 'categories/Hw0fYYhHg483eLsWRcQaTTZfhp4lhA8MDleUnXXW.jpg', 0, 2, 1, NULL, NULL, NULL, NULL, 0),
(11, '2026-04-19 14:38:20', '2026-04-25 10:57:55', 'مواد سباكة وصحية Plumbing and sanitary materials', 'Plumbing and sanitary materials', 'plumbing-and-sanitary-materials', 'fa-folder', 'مجموعة متكاملة من مواد السباكة والصحية عالية الجودة، تشمل الأنابيب، الوصلات، المحابس، المغاسل، والمراحيض. تتميز بمقاومة ممتازة للتسرب والصدأ والتآكل، بتصاميم عصرية تناسب جميع المشاريع السكنية والتجارية والصناعية.', 'categories/6jXxk3UCTkzZEnTjxHBVWeV6Zx8aXFU85M1VTv0O.jpg', 0, 12, 1, NULL, NULL, NULL, NULL, 0),
(12, '2026-04-25 10:55:47', '2026-04-25 10:57:07', 'التجهيزات المرورية وسلامة الطرق (Traffic Safety & Control)', 'Traffic Safety & Control', 'traffic-safety-control', 'fa-folder', 'مجموعة متكاملة من تجهيزات السلامة المرورية والتحكم في حركة المرور، تشمل الحواجز، المطبات الصناعية، العواكس، اللوحات الإرشادية، والأعمدة الواقية. تتميز بجودة عالية، مقاومة للظروف الجوية والصدمات، لضمان أعلى مستويات الأمان على الطرق والمواقف والمنشآت.\r\n\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', NULL, 0, 10, 1, NULL, NULL, NULL, NULL, 0);
