INSERT INTO `notification_templates` (`id`, `template_key`, `name`, `name_ar`, `subject`, `subject_ar`, `body`, `body_ar`, `type`, `variables`, `is_active`, `created_at`, `updated_at`) VALUES
(1, 'order_confirmed', 'Order Confirmed', 'تأكيد الطلب', 'Your order #{order_number} has been confirmed', 'تم تأكيد طلبك #{order_number}', 'Dear customer, your order #{order_number} has been confirmed and is being processed. Thank you for your purchase!', 'عزيزي العميل، تم تأكيد طلبك #{order_number} وهو قيد المعالجة. شكراً لشرائك!', 'email', '[\"order_number\",\"customer_name\"]', 1, '2026-06-23 15:13:31', '2026-06-23 15:13:31'),
(2, 'order_shipped', 'Order Shipped', 'شحن الطلب', 'Your order #{order_number} has been shipped', 'تم شحن طلبك #{order_number}', 'Great news! Your order #{order_number} has been shipped and is on its way to you. Tracking number: {tracking_number}', 'أخبار رائعة! تم شحن طلبك #{order_number} وهو في طريقه إليك. رقم التتبع: {tracking_number}', 'email', '[\"order_number\",\"tracking_number\",\"customer_name\"]', 1, '2026-06-23 15:13:39', '2026-06-23 15:13:39'),
(3, 'order_delivered', 'Order Delivered', 'تسليم الطلب', 'Your order #{order_number} has been delivered', 'تم تسليم طلبك #{order_number}', 'Your order #{order_number} has been successfully delivered. We hope you enjoy your purchase!', 'تم تسليم طلبك #{order_number} بنجاح. نأمل أن تستمتع بشرائك!', 'email', '[\"order_number\",\"customer_name\"]', 1, '2026-06-23 15:13:42', '2026-06-23 15:13:42'),
(4, 'order_cancelled', 'Order Cancelled', 'إلغاء الطلب', 'Your order #{order_number} has been cancelled', 'تم إلغاء طلبك #{order_number}', 'Your order #{order_number} has been cancelled. Reason: {reason}. If you have any questions, please contact us.', 'تم إلغاء طلبك #{order_number}. السبب: {reason}. إذا كان لديك أي أسئلة، يرجى الاتصال بنا.', 'email', '[\"order_number\",\"reason\",\"customer_name\"]', 1, '2026-06-23 15:13:48', '2026-06-23 15:13:48'),
(5, 'low_stock_alert', 'Low Stock Alert', 'تنبيه انخفاض المخزون', 'Low Stock Alert: {product_name}', 'تنبيه انخفاض المخزون: {product_name}', 'Product {product_name} is running low on stock. Current stock: {current_stock}, Minimum stock: {min_stock}. Please reorder soon.', 'المنتج {product_name} يعاني من انخفاض في المخزون. المخزون الحالي: {current_stock}، الحد الأدنى: {min_stock}. يرجى إعادة الطلب قريباً.', 'email', '[\"product_name\",\"current_stock\",\"min_stock\"]', 1, '2026-06-23 15:13:50', '2026-06-23 15:13:50'),
(6, 'out_of_stock', 'Out of Stock', 'نفاد المخزون', 'Out of Stock: {product_name}', 'نفاد المخزون: {product_name}', 'Product {product_name} is now out of stock. Please restock immediately.', 'المنتج {product_name} نفد من المخزون. يرجى إعادة التخزين فوراً.', 'email', '[\"product_name\"]', 1, '2026-06-23 15:13:53', '2026-06-23 15:13:53'),
(7, 'cycle_count_required', 'Cycle Count Required', 'مطلوب جرد دوري', 'Cycle Count Required for Zone {zone}', 'مطلوب جرد دوري للمنطقة {zone}', 'A cycle count is required for zone {zone} in warehouse {warehouse_name}. Please schedule the count.', 'مطلوب جرد دوري للمنطقة {zone} في المستودع {warehouse_name}. يرجى جدولة الجرد.', 'email', '[\"zone\",\"warehouse_name\"]', 1, '2026-06-23 15:13:54', '2026-06-23 15:13:54'),
(8, 'welcome_email', 'Welcome Email', 'بريد الترحيب', 'Welcome to Our Platform!', 'مرحباً بك في منصتنا!', 'Dear {name}, welcome to our platform! We are excited to have you with us. If you have any questions, feel free to reach out.', 'عزيزي {name}، مرحباً بك في منصتنا! نحن سعداء بانضمامك إلينا. إذا كان لديك أي أسئلة، لا تتردد في التواصل معنا.', 'email', '[\"name\"]', 1, '2026-06-23 15:13:54', '2026-06-23 15:13:54'),
(9, 'password_reset', 'Password Reset', 'إعادة تعيين كلمة المرور', 'Reset Your Password', 'إعادة تعيين كلمة المرور', 'Click the link below to reset your password: {reset_link}. This link will expire in 1 hour.', 'انقر على الرابط أدناه لإعادة تعيين كلمة المرور: {reset_link}. ستنتهي صلاحية هذا الرابط خلال ساعة واحدة.', 'email', '[\"reset_link\"]', 1, '2026-06-23 15:13:55', '2026-06-23 15:13:55');
