INSERT INTO `products` (`id`, `created_at`, `updated_at`, `category_id`, `name_ar`, `name_en`, `slug`, `description_ar`, `description_en`, `short_description_ar`, `short_description_en`, `seo`, `price`, `cost_price`, `tax_rate`, `taxable`, `unit`, `stock_quantity`, `min_stock`, `reorder_point`, `show_price`, `image_main`, `image_gallery`, `brand`, `model`, `sku`, `barcode`, `color`, `size`, `variant_group`, `in_stock`, `is_featured`, `views_count`, `sort_order`, `max_stock`, `weight`, `length`, `width`, `height`, `is_active`) VALUES
(1, '2026-03-09 09:07:27', '2026-04-25 10:51:52', 1, 'فتحة الاسطح للطوارئ والصيانة', 'Roof Hatch', 'architectural-building-solutions-roof-hatch', 'فتحة أسطح مصنوعة من الألمنيوم أو الفولاذ المجلفن، توفر وصولاً آمناً وسهلاً إلى الأسطح لأعمال الطوارئ والصيانة والتهوية. تصميم محكم الإغلاق يمنع تسرب المياه والهواء، مع نظام قفل أمان ومفصلات متينة تتحمل الظروف الجوية القاسية.\r\n\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Roof hatch made of aluminum or galvanized steel, providing safe and easy access to roofs for emergency, maintenance, and ventilation work. Tight-sealing design prevents water and air leakage, with a safety locking system and durable hinges that withstand harsh weather conditions.\r\n\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 1981.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/NVn1cQuVX4qEv4GVZu5HKAOL0oovIy6e4Su8sNaA.jpg', '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(2, '2026-03-09 09:07:27', '2026-04-19 12:55:30', 10, 'أنظمة حواجز الدرج', 'Handrail Systems', 'architectural-building-solutions-handrail-systems', 'أنظمة حواجز درج متينة ومصنوعة من مواد عالية الجودة (ستانلس ستيل، حديد، ألمنيوم)، توفر الأمان والثبات على السلالم والمنحدرات. تصميمات عصرية تناسب المباني السكنية والتجارية، مع سهولة التركيب ومقاومة ممتازة للصدأ والتآكل.\r\n\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Durable handrail systems made of high-quality materials (stainless steel, iron, aluminum), providing safety and stability on stairs and ramps. Modern designs suitable for residential and commercial buildings, with easy installation and excellent resistance to rust and corrosion.\r\n\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 2006.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/x410CqLrzhYGNE2EN8kAL3kHyhWpea5jUuSmsADH.jpg', '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(3, '2026-03-09 09:07:27', '2026-04-25 10:52:17', 1, 'نظام مرمى النفايات والبياضات', 'Garbage & Linen Chutes', 'architectural-building-solutions-garbage-linen-chutes', 'نظام مرمى متكامل للنفايات والبياضات، مصنوع من مواد مقاومة للحريق والصدمات، يستخدم في الفنادق والمستشفيات والمباني السكنية. يوفر حلاً نظيفاً وسريعاً لنقل النفايات والغسيل بين الطوابق مع عزل تام للروائح والضوضاء.\r\n\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Integrated garbage and linen chute system made of fire and impact-resistant materials, used in hotels, hospitals, and residential buildings. Provides a clean, fast solution for transporting waste and laundry between floors with complete odor and noise isolation.\r\n\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 3498.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/v7hV5EvHSJIJMJBVsokg5QR9rB6vUjPwqg3ilosc.jpg', '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(4, '2026-03-09 09:07:27', '2026-04-25 10:42:24', 1, 'أرضية مرتفعة للوصول', 'Access Raised Floor', 'architectural-building-solutions-access-raised-floor', 'أرضية مرتفعة قابلة للإزالة تسمح بالوصول السهل إلى الكابلات والأنابيب وأنظمة التبريد تحت الأرض. مثالية لمراكز البيانات وغرف الخوادم والمكاتب التقنية، توفر تهوية ممتازة ومرونة كاملة في إعادة التوزيع.\r\n\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Removable raised access floor allowing easy access to cables, pipes, and cooling systems beneath the surface. Ideal for data centers, server rooms, and technical offices, providing excellent ventilation and complete reconfiguration flexibility.\r\n\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 1894.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/EOm8fJLc0rqWIMQoOUGse7TFZgAbc1qSMfZ5bPuG.jpg', '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(5, '2026-03-09 09:07:27', '2026-04-25 10:42:59', 1, 'الخزائن', 'Lockers', 'architectural-building-solutions-lockers', 'خزائن معدنية متينة متعددة الأحجام والألوان، مثالية لتخزين الأغراض الشخصية في المدارس والشركات والصالات الرياضية. تصميم مقاوم للصدمات والصدأ مع أقفال أمان موثوقة وتهوية جيدة.\r\n\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Durable metal lockers available in various sizes and colors, ideal for storing personal belongings in schools, offices, and gymnasiums. Impact and rust-resistant design with reliable safety locks and good ventilation.\r\n\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 905.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/jn48Fb4hSsuFho5skoHtEXmywNBLJRC9VPduGV0y.jpg', '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
