(51, '2026-03-09 09:07:30', '2026-04-18 18:56:51', 6, 'صامولة طويلة (موصل)', 'Long Nut (Connector)', 'concrete-formwork-accessories-long-nut-connector', 'منتج عالي الجودة من إكسسوارات قوالب الخرسانة | Concrete Formwork Accessories', NULL, NULL, NULL, NULL, 4199.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/IXhhNeePbcT2MMTA4oZeIWfhCXQTdge1Tj2qwPch.jpg', '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(52, '2026-03-09 09:07:30', '2026-04-14 13:49:42', 5, 'غشاء البيتومين', 'Bitumen Membrane', 'waterproofing-thermal-insulation-bitumen-membrane', 'غشاء بيتومين عالي الجودة لعزل الأسطح والأساسات ضد تسرب الماء والرطوبة. يتميز بمرونة عالية ومقاومة ممتازة للأشعة فوق البنفسجية، ويوفر طبقة حماية متينة وسهلة التركيب باللهب أو اللاصق الذاتي.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'High-quality bitumen membrane for waterproofing roofs and foundations against water and moisture ingress. Features high flexibility and excellent UV resistance, providing a durable protective layer that is easy to install by torch or self-adhesive.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 1619.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/S3brROGkhfcVFli8JriB8Oe3br2hGwxMHU6fm6um.jpg', '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(53, '2026-03-09 09:07:30', '2026-04-14 13:50:33', 5, 'سائل عزل برايمر', 'Liquid Membrane praimer', 'waterproofing-thermal-insulation-liquid-membrane', 'سائل برايمر عازل من البيتومين المعدل، يستخدم لتجهيز الأسطح الخرسانية والمعدنية قبل تطبيق أغشية العزل. يتميز بقوة التصاق عالية، سريع الجفاف، ويسد المسامات لضمان سطح مثالي للعزل.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Modified bitumen liquid primer used for preparing concrete and metal surfaces before applying waterproofing membranes. Features high adhesion, fast drying, and seals pores to ensure an ideal surface for insulation.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 234.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/fHX08viIci4X1w19RubaF7iff2jGVODKZBxJH2LJ.png', '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(54, '2026-03-09 09:07:30', '2026-04-14 13:53:04', 5, 'الواح فلر بوردللحماية وللحشوات', 'Filler Board', 'waterproofing-thermal-insulation-filler-board', 'لوح حشو عازل عالي الكثافة يستخدم لملء الفواصل والتجاويف في أنظمة العزل الحراري والمائي. يتميز بقوة ضغط ممتازة، مقاوم للرطوبة، وسهل القص والتركيب ليناسب مختلف التطبيقات.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'High-density insulating filler board used for filling joints and cavities in thermal and waterproofing systems. Features excellent compressive strength, moisture resistance, and easy cutting and installation for various applications.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 1685.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/ICxv83zZACboPFOPPRWXqmTBsO1ZWrOOjerHvlwk.jpg', '[\"products\\/gallery\\/5XSu3M0QWCTpAKEBnMXyhrs2jh7LoThGR63ewvjt.jpg\",\"products\\/gallery\\/DNaNNiXdwk6cRXN0dKloBrb5oR1xU35l9ZGH5vGw.jpg\",\"products\\/gallery\\/vAHbBF6ZoMYEoA5MFIOUhIMHyCBBs5ZP3BTSAjWL.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(55, '2026-03-09 09:07:30', '2026-04-14 13:56:27', 5, 'لوحة الحماية بولي بروبولين', 'Protection Board', 'waterproofing-thermal-insulation-protection-board', 'لوح حماية عالي المتانة يستخدم لتغطية وحماية أغشية العزل المائي من التلف أثناء ردم الخنادق أو صب الخرسانة. يتميز بمقاومة عالية للصدمات والضغط، ويطيل عمر نظام العزل بشكل كبير.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'High-durability protection board used to cover and protect waterproofing membranes from damage during backfilling or concrete pouring. Features high impact and compression resistance, significantly extending the life of the insulation system.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 2089.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/tnt5Owxa4zoWindBHMmUzaCbfUIy9Dpv3iUn6jVy.png', '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(57, '2026-03-09 09:07:30', '2026-04-14 14:00:01', 5, 'قماش الجيوتكستايل', 'Geotextile Fabric', 'waterproofing-thermal-insulation-geotextile-fabric', 'قماش جيوتكستايل غير منسوج وعالي المسامية، يستخدم للفصل والترشيح والتعزيز في مشاريع الطرق والأساسات وأنظمة الصرف الصحي. يمنع اختلاط التربة بالحصى مع السماح بتصريف المياه بكفاءة.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Non-woven, high-permeability geotextile fabric used for separation, filtration, and reinforcement in road, foundation, and drainage system projects. Prevents soil from mixing with gravel while allowing efficient water drainage.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 1852.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/71FPZFs3Emra2q3Go2NBQvfAbyuq7AIpRQ0lio51.jpg', '[\"products\\/gallery\\/o31YYPbDR68V76KU08Wyu6KipAelKJJzys6V22Au.jpg\",\"products\\/gallery\\/i6N6qMGuU7XrskD3grY7JjD0jsGniFmeopt0Tz4b.jpg\",\"products\\/gallery\\/qRj1LO4inOM5q1XN5TSk12iaXiwIAOVkhMTfjRzS.jpg\",\"products\\/gallery\\/ppcivczDuXjP7ShdkyOxLK772FPRrnTX9Mp1S738.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(58, '2026-03-09 09:07:30', '2026-04-14 14:13:14', 5, 'وزرة ألمنيوم', 'Aluminum Flashing', 'waterproofing-thermal-insulation-polyethylene-flashing', 'وزرة ألمنيوم مرنة ومقاومة للصدأ، تستخدم لحماية حواف الأسطح والمناطق المعرضة للماء والرطوبة. تتميز بخفة الوزن وسهولة التشكيل والتركيب، وتمنع تسرب المياه خلف الواجهات والنوافذ بشكل فعال.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Flexible, rust-resistant aluminum flashing used to protect roof edges and areas exposed to water and moisture. Features light weight, easy shaping and installation, effectively preventing water leakage behind facades and windows.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 4871.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/fZNS1E62463z4uBljA26diN2wy835xQ6Gn3hIWGn.jpg', '[\"products\\/gallery\\/KXl3UgwD7EfMADAE2dmtYwh8xFUXLNUBDJSNdeyl.jpg\",\"products\\/gallery\\/wwGbdu4LwMVdIyDQiptUBNP2VAeFRCMG2MHbuG3X.jpg\",\"products\\/gallery\\/gwJ4oBq5wM33pTYKHEUb6Tffyh85ua6iUYG3oASP.jpg\",\"products\\/gallery\\/gidTDDTAgxAltRYrtpBJVUO0CKbdULjCOC208GpQ.jpg\",\"products\\/gallery\\/jeFB56vKlvlUvft98TrArGrLvjzQQtZLWpjFcMUg.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(60, '2026-03-09 09:07:30', '2026-04-14 14:17:16', 5, 'خابور تثبيت يعمل بالطرق', 'Hammer Anchor', 'waterproofing-thermal-insulation-hammer-anchor', 'خابور تثبيت بالطرق مصمم خصيصًا لتثبيت طبقات العزل المائي والحراري على الأسطح الخرسانية. يُدق مباشرة ، ويوفر تثبيتًا آمنًا وسريعًا مع رأس عريض يمنع تمزق أغشية العزل.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Hammer drive anchor specifically designed for fixing waterproofing and thermal insulation layers to concrete surfaces. Hammered directly , providing secure and fast fastening with a wide head that prevents tearing of insulation membranes.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 788.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/031GSSrEJT2smUtl9pvzhlvX4k0vkQ3MgLDU10xN.jpg', '[\"products\\/gallery\\/D6VeYur5NNGtVcBZwycGOWA2hTBUHQb6NfnXTM2B.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(61, '2026-03-09 09:07:30', '2026-04-18 19:12:06', 9, 'ريش دريل(فردتخريم ) للحديد والخشب والخرسانة', 'Drill Bits (Steel-Concrete-Wood)', 'waterproofing-thermal-insulation-drill-bits', 'ريش دريل عالية الجودة متعددة الاستخدامات، مصممة لتخريم الحديد والخشب والخرسانة بدقة وسرعة. تتميز برؤوس كربيدية شديدة التحمل، مقاومة للتآكل والحرارة العالية، وتناسب جميع أنواع المثاقب الكهربائية والبطارية.\r\n\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'High-quality, multi-purpose drill bits designed for drilling through steel, concrete, and wood with precision and speed. Feature durable carbide tips, resistant to wear and high heat, suitable for all types of electric and cordless drills.\r\n\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 4395.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/haxDsj6eZ5p7qvjCtkT2gmVpN0eg4bLUhJ9oyz7F.jpg', '[\"products\\/gallery\\/MyfOn513bf5retuNR3nsVd7U8Zo6M1Yi3ihdSoiN.jpg\",\"products\\/gallery\\/AP9SkIj0NiQqvp2mg11hEhVZccfoSeGViSoJojmN.jpg\",\"products\\/gallery\\/B2Q4otnIF59xgeG61OnaBIpAQEFRLNQqBagWWKDE.jpg\",\"products\\/gallery\\/zPquZ2CmTd1uK7EyhzPZQKedB6DPwr1QcfJFcn5w.jpg\",\"products\\/gallery\\/3KyUFPXmVbtqMW75E0dBEdNpszMlQ8seh3buL3DJ.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(63, '2026-03-09 09:07:30', '2026-04-14 14:20:38', 5, 'بوليسترين مبثوق', 'Extruded Polystyrene', 'waterproofing-thermal-insulation-extruded-polystyrene-xps', 'ألواح بوليسترين مبثوق (XPS) عالية الكثافة، تستخدم للعزل الحراري للأساسات والأسطح والجدران الخارجية. تتميز بمقاومة ممتازة للرطوبة والضغط، وخفة الوزن، ومعامل توصيل حراري منخفض جدًا.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'High-density extruded polystyrene (XPS) boards used for thermal insulation of foundations, roofs, and exterior walls. Feature excellent moisture and compression resistance, light weight, and a very low thermal conductivity coefficient.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 2710.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/qsXBBj9E6c6dAdonxeDwhv2wBcqUtR6ufnn0MPrn.jpg', '[\"products\\/gallery\\/4jLqu84wVLRqBQA19V9u942cc1HsQG52wxktr86Q.jpg\",\"products\\/gallery\\/iHqGuMnUy0L13VlGMy1QQDDj683PDRMzVKlAnwc4.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(64, '2026-03-09 09:07:30', '2026-04-14 14:22:42', 5, 'بوليسترين موسع', 'Expanded Polystyrene', 'waterproofing-thermal-insulation-expanded-polystyrene-eps', 'ألواح بوليسترين موسع (EPS) خفيفة الوزن وعالية الكفاءة، تستخدم للعزل الحراري للجدران والأسقف والأرضيات. تتميز بمرونة ممتازة، مقاومة جيدة للرطوبة، وسهولة في القص والتركيب بأسعار اقتصادية.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Lightweight, high-efficiency expanded polystyrene (EPS) boards used for thermal insulation of walls, ceilings, and floors. Feature excellent flexibility, good moisture resistance, and easy cutting and installation at economical prices.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 4224.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/4UG9B2YlKOPsSoga4ecGG7w5FFxkgkKSUYaj1YbK.jpg', '[\"products\\/gallery\\/d5cNqGKNoUZscwHVxOmyEV11S5JZJge0Tr4PidgS.jpg\",\"products\\/gallery\\/RnaJZWvxtdt6EaOWetJ71MmKt5Ljr1NsqAAtzVtU.jpg\",\"products\\/gallery\\/9bpd3OAOggyFpUaPWURcArkY7DELpODX6VDNNE7j.jpg\",\"products\\/gallery\\/a6IPvisSkwtt6b2mibedpV4KzS3EBqHwu0BLHSF1.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(65, '2026-03-09 09:07:30', '2026-04-16 09:27:09', 5, 'الصوف الصخري', 'Rock Wool', 'waterproofing-thermal-insulation-rock-wool', 'ألواح الصوف الصخري عالية الكثافة، عازل حراري وصوتي ممتاز ومقاوم للحريق حتى 1000 درجة مئوية. يستخدم للأسقف والجدران والواجهات، ويمنحك توفيراً في الطاقة وحماية فائقة.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'High-density rock wool boards, an excellent thermal and acoustic insulator with fire resistance up to 1000°C. Used for roofs, walls, and facades, providing energy savings and superior protection.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 3723.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/VTAdB7neMICzDTQ9GnrOTdKZ0I5Gwisvc8QfZPij.jpg', '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(66, '2026-03-09 09:07:31', '2026-04-14 12:56:26', 6, 'مشبك الشريط', 'Strap Clamp', 'pipe-clamps-hangers-fixings-strap-clamp', 'مشبك شريطي فولاذي مرن وعالي التحمل، يستخدم لتعليق وتثبيت الأنابيب والقنوات الكهربائية بكفاءة. يتميز بسهولة الثني والتعديل ليتناسب مع مختلف الأحجام ويوفر تثبيتًا آمنًا ضد الاهتزاز.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Flexible, high-strength steel strap clamp used for efficiently hanging and securing pipes and electrical conduits. Features easy bending and adjustment to fit various sizes and provides secure vibration-resistant fastening.', NULL, NULL, NULL, 1634.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/HBrknXR8huejn650zKhuYMmdgsuShwu5TFENAYqW.jpg', '[\"products\\/gallery\\/Nmbf3evpaacKVd7Pw7YAPya7VPaw4GAL1QMUVHNs.jpg\",\"products\\/gallery\\/2IwHGDesXDOLLlrvGOoxdPFuJqDTmZovc3JqjfIR.jpg\",\"products\\/gallery\\/KEvHZmDyValA6k93KxSx1SLY2g0Z0wBvgGNrxgnh.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(67, '2026-03-09 09:07:31', '2026-04-14 12:51:10', 6, 'مشبك U', 'U-Clamp', 'pipe-clamps-hangers-fixings-u-clamp', 'مشبك U فولاذي متعدد الاستخدامات لتثبيت وتعليق الأنابيب والخراطيم والقنوات بسهولة وأمان. يتميز بقوة تحمل عالية وسهولة في التركيب ومقاومة ممتازة للاهتزاز والصدأ.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Versatile steel U-clamp for easily and securely fastening and hanging pipes, hoses, and channels. Features high load capacity, easy installation, and excellent resistance to vibration and rust.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 2786.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/UfNhEO0i1nIewbM7Dxl1YcGxLbe7aU9eCRlDVhTI.jpg', '[\"products\\/gallery\\/6VX3G3PZ0nGd7AUThLrS9JO5w4yfdS72VuYvxFgE.jpg\",\"products\\/gallery\\/cwrq734LZKPWMBMLf3nupNBRMjjjFRDSzd7tpKxz.jpg\",\"products\\/gallery\\/9e3aC6bD4iBwoSiTCgvWVWPPBFX5W6Wsll8qTNRM.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(68, '2026-03-09 09:07:31', '2026-04-14 12:54:08', 6, 'مشبك الأنابيب', 'Pipe Clamp', 'pipe-clamps-hangers-fixings-pipe-clamp', 'مشبك أنابيب معدني مزود بطبقة مطاطية داخلية لعزل الصدمات والاهتزازات وحماية الأنابيب من الاحتكاك. يوفر تثبيتًا آمنًا ومحكمًا مع تقليل الضوضاء وإطالة عمر الأنابيب.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Metal pipe clamp with an inner rubber lining to isolate shocks and vibrations and protect pipes from friction. Provides secure, tight fastening while reducing noise and extending pipe life.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 461.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/PERI42s3gLpKCF3U3HRvCECU2PilwuAcY4R35bjb.jpg', '[\"products\\/gallery\\/CeGTyirqDhzTPPJjoFOTnC8BrZM7Yc5O8oaOqajV.jpg\",\"products\\/gallery\\/SutDv0p6bUtsYUgNJJNaA4SmN4isM8tvOTOG5TSP.jpg\",\"products\\/gallery\\/AmvKR9ZSQa9LhxPGc14FD6aPfvUpX28N4beARzfH.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(69, '2026-03-09 09:07:31', '2026-04-14 12:58:54', 6, 'مشبك دوار', 'Swivel Clamp', 'pipe-clamps-hangers-fixings-swivel-clamp', 'مشبك دوار متعدد الزوايا مصنوع من الفولاذ المقاوم للصدأ، يسمح بتثبيت الأنابيب في أي اتجاه بفضل تصميمه القابل للدوران 360 درجة. مثالي للأماكن الضيقة والتركيبات المائلة والصعبة.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Multi-angle swivel clamp made of stainless steel, allows pipes to be secured in any direction thanks to its 360-degree rotatable design. Ideal for tight spaces, angled, and difficult installations.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 2658.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/CiH07ILlUFWSuPiVb7uNP1pF20STEVoD2rRDaSOD.jpg', '[\"products\\/gallery\\/MR3Rj8JJ4cMu6vJQdbCCebRIkPSgytW7syrcRG34.jpg\",\"products\\/gallery\\/ZNUwYuvIzLapECLg3azqQ8JAYzeCYEDJQXMq7cbq.jpg\",\"products\\/gallery\\/u6VHpvMoH8MBr07EU9XJmyOt8gdrflVISLpLLPk8.jpg\",\"products\\/gallery\\/SBVc7dwLmzRqTl9ABn4Y3oS59jLPGj6SXiGnU7nQ.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(70, '2026-03-09 09:07:31', '2026-04-14 13:01:33', 6, 'مشبك كليفيس', 'Clevis Clamp', 'pipe-clamps-hangers-fixings-clevis-clamp', 'مشبك كليفيس فولاذي مقوى على شكل حرف U، يستخدم لتعليق وتثبيت الأنابيب العمودية والأفقية في أنظمة التكييف والسباكة. يوفر مرونة في الحركة مع تثبيت آمن ومقاومة عالية للأحمال الثقيلة.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Reinforced steel clevis clamp in a U-shape, used for hanging and securing vertical and horizontal pipes in HVAC and plumbing systems. Provides flexibility with secure fastening and high resistance to heavy loads.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 696.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/qWufw2avUCsI1EOPaEewIFlsEV2qjEPxdbRY4Y8w.jpg', '[\"products\\/gallery\\/2GySNTr4rQbtdkl15Tle9T9V4o0tZ4vWrNRtgWaA.jpg\",\"products\\/gallery\\/tyO03hiIY3c8YOJjvAEqN7Lmo0s4SEyN0ilam8Dw.jpg\",\"products\\/gallery\\/nqi1gLIZV2tNp5zBt53cn5sVM9wOL9MRgJJ8JMZu.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(72, '2026-03-09 09:07:31', '2026-04-14 13:05:15', 6, 'كلبس القناة', 'Channel clamp', 'pipe-clamps-hangers-fixings-channel', 'كلبس قناة فولاذي متين يستخدم لتثبيت وتعليق القنوات المعدنية والأنابيب على الأسقف والجدران. يتميز بسهولة التركيب والضبط، ويوفر تثبيتًا آمنًا مقاومًا للاهتزاز والتآكل.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Durable steel channel clamp used for securing and hanging metal channels and pipes to ceilings and walls. Features easy installation and adjustment, providing secure fastening resistant to vibration and corrosion.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 1014.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/ojcBXNvt198vbZrLhyCuuEyCZ5RPdQx3xK0k4Av8.png', '[\"products\\/gallery\\/Fc7esGngLgydiJfIgwVmWWeTBhHAlBXSO3MUzw3P.jpg\",\"products\\/gallery\\/jYYemxYAHOcjd7rTkfwZ4SUKrR5mvtfICqzdvDBG.jpg\",\"products\\/gallery\\/3bq5L30xwAsxdcBVlU7lX6gwdSFHalOzyxhn3QAk.jpg\",\"products\\/gallery\\/5IVHSEh9mlLewwefpHdIAMO0tuQeTULmTpGSi6Xo.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(73, '2026-03-09 09:07:31', '2026-04-14 13:08:39', 6, 'مشبك العارضة', 'Beam Clamp', 'pipe-clamps-hangers-fixings-beam-clamp', 'مشبك عارضة فولاذي عالي التحمل، يُثبت مباشرة على العوارض الحديدية والخشبية دون حاجة للحفر. مثالي لتعليق الأنابيب والقنوات والمعدات الثقيلة بسرعة وأمان مع توزيع مثالي للأحمال.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Heavy-duty steel beam clamp that attaches directly to steel and wooden beams without drilling. Ideal for quickly and safely hanging pipes, channels, and heavy equipment with perfect load distribution.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 3288.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/0VLme8Bbdhdg1P4BfNTN5pBQFbItARl55bLhPSaL.jpg', '[\"products\\/gallery\\/UJlrS63smlq4mdywv3IXGkOJXRxIlnW4Uh22MSoi.jpg\",\"products\\/gallery\\/60BnVckCVp59vyguS5KiKjEcD5vVN1KDxR3Cu3DH.jpg\",\"products\\/gallery\\/wbAiHpwSx6AQ1W3ymu2snNTXxhuMSS44jog1qOAi.jpg\",\"products\\/gallery\\/i4yffmEEVpuY98jUO0nl5nLcoLipgfbAb4F5BOrf.jpg\",\"products\\/gallery\\/jVmrM1hMsrP4yzkeWNfS4YNr6F2kkYCSZOvQ5AEN.jpg\",\"products\\/gallery\\/OKxYZe96aDVdp9wB9pm8xFG49rarwoGeP2Rab7gU.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(74, '2026-03-09 09:07:31', '2026-04-14 13:11:45', 6, 'مشبك البراغي', 'Bolt Clamp', 'pipe-clamps-hangers-fixings-bolt-clamp', 'مشبك براغي فولاذي مزدوج التثبيت، يستخدم لربط وتجميع الأنابيب مع بعضها أو تثبيتها على الأسطح. يتميز بقوة شد عالية وسهولة في الفك والتركيب مع مقاومة ممتازة للاهتزاز.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Dual-fastening steel bolt clamp used for connecting pipes together or securing them to surfaces. Features high tightening strength, easy assembly and disassembly, and excellent vibration resistance.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 1974.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/SuSOpdr8hEpvqNfTsswPkO5RWQ5vnb61elT3LIbS.jpg', '[\"products\\/gallery\\/SSpct2pVJZTX557WIcsGPtooSuBR2Vi4673zammX.jpg\",\"products\\/gallery\\/PvMUjVP4dl9tUBBlZxZJpOEX5O1FXBZutQVXUVQA.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(75, '2026-03-09 09:07:31', '2026-04-14 13:14:02', 7, 'لوح الجبس', 'Gypsum Board', 'gypsum-partitions-suspended-ceilings-gypsum-board', 'لوح جبس عالي الجودة، مثالي للأسقف والجدران الداخلية، يتميز بمقاومة جيدة للحريق وعزل صوتي ممتاز. سطح أملس وسهل التشطيب والتركيب.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'High-quality gypsum board, ideal for ceilings and interior walls, featuring good fire resistance and excellent sound insulation. Smooth surface for easy finishing and installation.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 1519.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/XMAu2w2yu25U5bS1JpuPQHaQ2Z2yKbK6oylbPV5w.jpg', '[\"products\\/gallery\\/jR6fE3CfSav6dFQ5NDOc5N6LsZ6p2cjFaNzCxP1r.jpg\",\"products\\/gallery\\/eKvtbOOV5AFocZOtzCicooqsFQKF1T0H8XVbeIBp.jpg\",\"products\\/gallery\\/GqEOtwxQtXy2s5LvvGo0P8WnzJzt304AIbCDXPoZ.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(76, '2026-03-09 09:07:31', '2026-04-14 13:16:05', 7, 'لوح الأسمنت', 'Cement Board', 'gypsum-partitions-suspended-ceilings-cement-board', 'لوح أسمنتي متين مقاوم للماء والحريق، مثالي للاستخدام في الحمامات والمطابخ والواجهات الخارجية. يوفر قاعدة صلبة لتركيب السيراميك والرخام مع ثبات عالي ضد الرطوبة.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Durable cement board resistant to water and fire, ideal for use in bathrooms, kitchens, and exterior facades. Provides a solid base for installing ceramic tiles and marble with high stability against moisture.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 669.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/n9sjZ1ZO4rGTZSKn4MFU43lsO5gPxlFMtPL54TqN.jpg', '[\"products\\/gallery\\/t5XJEu5vs1YKwBWOWQbQCnIEeduDiAr4tnx8mtSV.jpg\",\"products\\/gallery\\/kFPGCJNSfJaSLtJdsGA0e74rNqwCPOOLGMa34NZH.jpg\",\"products\\/gallery\\/22L4yOMHTEetMUOtVVqezbIAiro8sqEdyC4Wkq7u.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(77, '2026-03-09 09:07:31', '2026-04-14 13:17:43', 7, 'معجون الجبس', 'Gypsum Putty', 'gypsum-partitions-suspended-ceilings-gypsum-putty', 'معجون جبس ناعم وسهل التشطيب، يستخدم لسد الفواصل وتغطية رؤوس البراغي وتنعيم أسطح ألواح الجبس. يتميز بقوة التصاق عالية وجفاف سريع يمنحك سطحاً أملساً جاهزاً للدهان.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Smooth, easy-to-finish gypsum putty used for sealing joints, covering screw heads, and smoothing gypsum board surfaces. Features high adhesion and fast drying, giving you a smooth surface ready for painting.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 1740.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/mj2PGUSZ3C49aufZQ0oOl4eZJSUqdeyRfQTx5zqd.jpg', '[\"products\\/gallery\\/VUGmYMHvG08lGKHRLQkdJZd43Qi6uDLohYl6tCoV.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(78, '2026-03-09 09:07:31', '2026-04-14 13:20:25', 7, 'الدعامات والقواعد', 'Stud & Runner', 'gypsum-partitions-suspended-ceilings-stud-runner', 'دعامات وقواعد معدنية مجلفنة عالية الجودة، تشكل الهيكل الأساسي لقواطع الجبس والأسقف المعلقة. تتميز بالدقة في الأبعاد وسهولة التركيب، وتمنحك نظاماً قوياً ومستقيماً طويل الأمد.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'High-quality galvanized metal studs and runners forming the essential framework for gypsum partitions and suspended ceilings. Feature precise dimensions and easy installation, providing a strong, straight, long-lasting system.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 3614.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/y7LVN8nPZE4EGD8Zs4t4CuCujVGOE8ZDkbYXhK3T.png', '[\"products\\/gallery\\/PYruCyoB8z5HZ50bFhtqTl6oPqCDDGw8AQbCXPXh.jpg\",\"products\\/gallery\\/kO9wD5S5B0PTXc0qFUDrNA1yoDOpXBsCf2MgMDJx.jpg\",\"products\\/gallery\\/T8LFS5BlP4nGJ9xd7mSLFWdEiwGLlQTDQcoqHcw0.jpg\",\"products\\/gallery\\/eNsMZ62e6THHrABaDXPEJyISGEtN7kSh43iGMuyE.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(79, '2026-03-09 09:07:31', '2026-04-14 13:23:14', 7, 'شريط شبك فاصل جدار جبس', 'Joint Mesh Tape', 'gypsum-partitions-suspended-ceilings-joint-tape', 'شريط شبكي من الألياف الزجاجية ذاتية اللصق، يستخدم لتقوية فواصل ألواح الجبس ومنع التشققات. يتميز بمرونة عالية ومقاومة للقلويات، ويمنحك وصلات متينة وسطحاً أملس طويل الأمد.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Self-adhesive fiberglass mesh tape used for reinforcing gypsum board joints and preventing cracks. Features high flexibility and alkali resistance, giving you durable joints and a long-lasting smooth surface.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 4850.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/zAiSXf00KE1y1doMPpPJsbGJPWL0b2dtG2tszuri.jpg', '[\"products\\/gallery\\/LTGN2Im7gBb8J6UwGuvlJkjXYSOoX9X4GMij8sNy.jpg\",\"products\\/gallery\\/50VCgmUYz3sAOGoyzTIvF208RSgQij5pNAmiIy2N.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(80, '2026-03-09 09:07:31', '2026-04-14 13:25:35', 7, 'زاوية جدران جبسية', 'Wall Angle', 'gypsum-partitions-suspended-ceilings-wall-angle', 'زاوية جدار جبسي معدنية مجلفنة، تستخدم لتثبيت وتوجيه ألواح الجبس عند التقاء الجدران مع الأسقف. تتميز بالدقة والصلابة، وتمنحك زوايا مستقيمة وحواف نظيفة واحترافية عالية.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Galvanized metal gypsum wall angle used for fixing and directing gypsum boards where walls meet ceilings. Features precision and rigidity, giving you straight corners, clean edges, and high professionalism.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 1708.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/H5mo38JKTJXBN38jYRNJHYiHLBCUpGz1cV4Y4puU.jpg', '[\"products\\/gallery\\/Vf73ux3w6h6NlQpR50baGyyVdzVNrQ52jze5KWnk.jpg\",\"products\\/gallery\\/KgiiHOtItrVkCNRH2XEjsoNp40lAWOW4aOWbneTd.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(81, '2026-03-09 09:07:31', '2026-04-14 13:28:15', 7, 'قناة تثبيت اسقف مستعارة (اوميغا)(الفورينج)', 'Furring Channel ) Omega)', 'gypsum-partitions-suspended-ceilings-furring-channel', 'قناة أوميغا (الفورينج) المعدنية المجلفنة، تستخدم كقاعدة رئيسية لتثبيت ألواح الجبس في الأسقف المستعارة والجدران. تصميمها على شكل حرف Omega يمنحك صلابة عالية وسهولة في التسوية والتركيب.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Galvanized metal Omega (furring) channel used as a main framework for fixing gypsum boards in suspended ceilings and walls. Its Omega-shaped design provides high rigidity and easy leveling and installation.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 772.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/ithArfGU0tX902GnbUcv1JpkJkwUtwCq6i6ptlJd.jpg', '[\"products\\/gallery\\/s2CJ9jCe6Q7emmUqDn8e6hsIsAHIFnXlH6sP43e2.jpg\",\"products\\/gallery\\/OQ2vtwpVGqMBKJfsZ269y1ffYY7NVKtKEw5GWs5T.jpg\",\"products\\/gallery\\/hLkuGq2OiJph6B29zEIaW8cC9cBYAvu5UrThBNyj.jpg\",\"products\\/gallery\\/IaPNOuVqe87h4b5Q8DYH1y96phsNY80yfwydKYEu.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(85, '2026-03-09 09:07:31', '2026-04-14 13:33:51', 7, 'مشبك زنبركي قابل للتعديل لتثبيت الأسقف المستعارة', 'Adjustable Spring Clip', 'gypsum-partitions-suspended-ceilings-adjustable-spring-clip', 'مشبك زنبركي قابل للتعديل مصمم لتعليق وتثبيت الأسقف المستعارة بمرونة عالية. يمتص الاهتزازات ويسمح بتسوية الأسقف بسهولة مع توزيع مثالي للأحمال دون الحاجة إلى لحام أو أدوات معقدة.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Adjustable spring clip designed for hanging and fixing suspended ceilings with high flexibility. Absorbs vibrations and allows easy ceiling leveling with ideal load distribution without welding or complex tools.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 861.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/qok5XymUifGVOHKUVJ1Jd2yTileDWxehUqmSRwTR.jpg', '[\"products\\/gallery\\/xJ1Ynvh3UFvLfnyII5ZZbzB47NGxmISmkYu8rCyJ.jpg\",\"products\\/gallery\\/T2RgfihIQBnWbCGGSXc8F5XjUwFBYOEIHjGonNAz.jpg\",\"products\\/gallery\\/0sDRvnpWmsUqvNoNxwt88rP0nBZxsSw0b1KxTypz.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(88, '2026-03-09 09:07:32', '2026-04-18 19:09:07', 6, 'خابور حديد سقفي', 'Drop-in Anchor', 'gypsum-partitions-suspended-ceilings-drop-in-anchor', 'خابور حديد سقفي عالي التحمل، يُستخدم لتثبيت الأحمال الثقيلة في الأسقف الخرسانية بدقة وأمان. يوفر قفلًا داخليًا موثوقًا ومقاومة ممتازة للاهتزاز.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Heavy-duty steel drop-in anchor used for securely fastening heavy loads to concrete ceilings with precision and safety. Provides reliable internal locking and excellent vibration resistance.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 182.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/t9vU8BhD0pPKc8WJ8mdVuC4bZee62U5GfLeBjvaC.jpg', '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(89, '2026-03-09 09:07:32', '2026-04-14 11:35:18', 7, 'شريط ورقي لوصلات الجبس', 'Gypsum Joint paper tape', 'gypsum-partitions-suspended-ceilings-g-corner-tape-corner-tape', 'شريط ورقي مثقوب عالي الجودة لتقوية وصلات ألواح الجبس ومنع التشققات. يتميز بمسامية ممتازة لالتصاق المعجون ويمنحك سطحاً أملس ومتيناً.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'High-quality perforated paper tape for reinforcing gypsum board joints and preventing cracks. Features excellent porosity for compound adhesion, giving you a smooth and durable surface.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 3345.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/svu42Jgnq7L1GWSV8J84qUReOLbWPYN6lki9jkoQ.jpg', '[\"products\\/gallery\\/C29bPwxADitLiJgsqArWAJii55JdSjdpeUUqd1SG.jpg\",\"products\\/gallery\\/0HLS0fwXaR2wnsz5lO2HGd1iZ0yxrprYdzL9ghlt.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(90, '2026-03-09 09:07:32', '2026-04-14 11:57:38', 8, 'حوامل جدارية لزوايا الانظمة الميكانيكية', 'Unistrut Channel', 'cladding-facade-accessories-unistrut-channel', 'حوامل جدارية فولاذية متعددة الاستخدامات لتركيب وتثبيت زوايا الأنظمة الميكانيكية والكهربائية والسباكة. تصميم مرن عالي التحمل يسمح بتعديل الزوايا بسهولة وأمان.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Versatile steel wall brackets for installing and securing mechanical, electrical, and plumbing system angles. A flexible, heavy-duty design allows for easy and safe angle adjustments.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 2314.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/McwIS1ikfKuB1qZyXhmbqsV1H5McHTQzT7jHR6gb.jpg', '[\"products\\/gallery\\/Yqf7aOGjTX0bt170JtPaLaBmeQprXXgrA7bpSfiR.jpg\",\"products\\/gallery\\/OnexpVlLWIysC9AJtUqF5miUbCOW6eic91IGG59Z.jpg\",\"products\\/gallery\\/x8bpbui60fU0DsAIqEzrZ6jSiRAF9i92SzAw8p6Z.jpg\",\"products\\/gallery\\/HpTUPm9LBsAEGOHRLomxdzjEJTISDeVlC7BZbQHo.png\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(91, '2026-03-09 09:07:32', '2026-04-14 12:00:22', 6, 'سيخ مسنن شرار', 'Threaded Rod', 'threaded-rod', 'سيخ مسنن عالي الجودة من الصلب، مثالي للتطبيقات الإنشائية وتعليق الأنظمة الميكانيكية والكهربائية. قوة شد ممتازة وسهولة في القص والتركيب مع الصواميل.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'High-quality steel threaded rod, ideal for structural applications and hanging mechanical and electrical systems. Excellent tensile strength and easy cutting and installation with nuts.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 3467.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/5Kl25EreHsFpBRMvCxADzB0Vew63h6nh57aLNysd.jpg', '[\"products\\/gallery\\/XsDZIrZVywhnkwNEbluCoy3K2qtQxdsDmVFQbHBR.jpg\",\"products\\/gallery\\/gwxrcuQIPUmvxM9G1VEMbq46dVxRMSR1kcdaVB5d.jpg\",\"products\\/gallery\\/smx8d7BOjnODFDUnfFvH5fXzDRCM92uKk09MEp31.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(92, '2026-03-09 09:07:32', '2026-04-14 12:02:29', 8, 'صامولة زنبركية', 'Spring Nut', 'cladding-facade-accessories-spring-nut', 'صامولة زنبركية فولاذية سهلة التركيب تنزلق بسلاسة داخل القنوات المعدنية لتثبيت البراغي والمعدات. تصميم مرن يمنحك قفلًا آمنًا ومقاومًا للاهتزاز دون الحاجة لحام.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Steel spring nut that slides smoothly inside metal channels for securing bolts and equipment. A flexible design provides a secure, vibration-resistant lock without the need for welding.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 2382.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/6o0KnULWPVrZ47Oq6i2jsqRihSkzodbyX54fVAgD.jpg', '[\"products\\/gallery\\/KHZgqi5DV7y7A6HsHlkVbOSp59pvdaUBn3LOJQiy.jpg\",\"products\\/gallery\\/H8a5xDSkjp9FPNpOj851J5kCKzxduguOjEC0nSu3.jpg\",\"products\\/gallery\\/LgQTn7soJ9dZ1RmDVHLSQxjxtvJVKCkDPWcMPPi1.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
(93, '2026-03-09 09:07:32', '2026-04-14 12:07:22', 8, 'زوايا تثبيت رخام ميكانيكية', 'Mechanical Bracket', 'cladding-facade-accessories-bracket', 'زوايا معدنية ميكانيكية مصممة خصيصًا لتثبيت الرخام والحجر على الواجهات والجدران دون الحاجة إلى مواد لاصقة. تمنحك توزيعًا مثاليًا للأحمال وثباتًا طويل الأمد.\r\nلطلب الكتالوج الخاص بالمنتج، نرجو التواصل على أرقام الاتصال الموجودة بالموقع.', 'Metal mechanical brackets specifically designed for installing marble and stone on facades and walls without the need for adhesives. Provide ideal load distribution and long-lasting stability.\r\nTo request the product catalog, please contact us via the phone numbers listed on the website.', NULL, NULL, NULL, 987.00, NULL, NULL, 0, NULL, 0, 0, NULL, 1, 'products/ShUU3kREd57T37ANZZhwf7ISu71SE8z1yj0fqoWI.jpg', '[\"products\\/gallery\\/EKEsyJNkuvOoCB0DgmZAoTQQ8wu2504hC6NRoqm8.jpg\",\"products\\/gallery\\/odUFHVLeXnJtwsuBJmCtNLpJrV2VpuVyUKxetlq3.jpg\",\"products\\/gallery\\/yfPOrq0GGQVjL9Qp3MgY9xzFIDEJDhfIplNcsII6.jpg\",\"products\\/gallery\\/cDdct3e0Wrxm2y1Wuh5Gy2A8ht95nLSG9lxk9XJl.jpg\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 1),
